import QRCode from "qrcode";
import { normalizeText, toQrOptions } from "./shared.js";
export async function renderTerminal(text, options = {}) {
    return await QRCode.toString(normalizeText(text), {
        ...toQrOptions(options),
        small: options.small ?? true,
        type: "terminal",
    });
}
export async function renderUtf8(text, options = {}) {
    return await QRCode.toString(normalizeText(text), {
        ...toQrOptions(options),
        type: "utf8",
    });
}
